-- ------------------------------------------------------------
-- 13. KB SOURCES  (Knowledge Base provenance)
-- Tracks every source document ingested into the vector store.
-- Powers the Admin Portal "KB freshness" panel.
-- ------------------------------------------------------------
CREATE TABLE IF NOT EXISTS kb_sources (
    id                  TEXT PRIMARY KEY,
    source_name         TEXT NOT NULL,
    source_url          TEXT NOT NULL,
    category            TEXT NOT NULL,
    state_or_all_india  TEXT NOT NULL DEFAULT 'ALL_INDIA',
    last_verified_date  TEXT NOT NULL,   -- ISO-8601 date
    version             TEXT NOT NULL,   -- e.g. "2025-Q2-v1"
    document_count      INTEGER NOT NULL DEFAULT 0,
    ingest_status       TEXT NOT NULL DEFAULT 'PENDING'
                            CHECK (ingest_status IN ('PENDING','INGESTED','FAILED','STALE')),
    created_at          TEXT NOT NULL,
    updated_at          TEXT NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_kbs_category ON kb_sources(category);
CREATE INDEX IF NOT EXISTS idx_kbs_verified ON kb_sources(last_verified_date);


-- ============================================================
-- END OF SCHEMA
-- ============================================================
